# Auto-generated by connectome-cook for the triumvirate-mid example.
#
# Caddy fronts the conhost WebUI; the conhost service does not bind a host
# port directly, so requests have to come through here. WebSocket upgrades
# pass through automatically (Caddy preserves the Upgrade/Connection +
# Origin headers).
#
# To go to production:
#   - Replace `:80` with a real domain (e.g. `admin.example.com {`).
#     Caddy will provision a Let's Encrypt cert automatically.
#   - Either remove the conhost-side basicAuth and add `basic_auth` here
#     (so Caddy is the single auth boundary), or keep both layers.
#   - Set CADDY_BIND=0.0.0.0 in .env so the host port isn't loopback-only.

:80 {
	encode gzip zstd

	reverse_proxy triumvirate-mid:7340 {
		header_up X-Forwarded-Proto {scheme}
		header_up X-Real-IP {remote_host}
	}

	log {
		output stdout
		format console
	}
}
